import { useState } from "react";

function MovieItem({ movie, onDelete, onUpdate, onSelect }) {
    const [isEditing, setIsEditing] = useState(false);
    const [editedTitle, setEditedTitle] = useState(movie.title);

    const handleSave = () => {
        if (editedTitle.trim() === "") return;
        onUpdate(movie.id, editedTitle);
        setIsEditing(false);
    };

    return (
        <li className="movie-card">
            <img
                src={movie.poster}
                alt={movie.title}
                onClick={() => onSelect(movie)}
                style={{ cursor: 'pointer' }}
                onError={(e) => {
                    e.target.src = "https://via.placeholder.com/300x450?text=No+Image";
                }}
            />

            <div className="movie-details">
                {isEditing ? (
                    <input
                        type="text"
                        className="edit-input"
                        value={editedTitle}
                        onChange={(e) => setEditedTitle(e.target.value)}
                        autoFocus
                    />
                ) : (
                    <h3 onClick={() => onSelect(movie)}>{movie.title}</h3>
                )}

                <div className="buttons">
                    {isEditing ? (
                        <button className="save-btn" onClick={handleSearch}>💾 Save</button>
                    ) : (
                        <button className="edit-btn" onClick={() => setIsEditing(true)}>✏️ Edit</button>
                    )}
                    <button className="delete-btn" onClick={() => onDelete(movie.id)}>🗑️ Delete</button>
                </div>
            </div>
        </li>
    );
}

export default MovieItem;
